    question: "Use LINQ to filter and sort data.",
    mathSolution: "from n in numbers where n > 5 orderby n descending select n",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers = { 5, 2, 8, 1, 9, 3, 7, 4, 6 };\n        \n        var sorted = from n in numbers\n                     where n > 3\n                     orderby n descending\n                     select n;\n        \n        Console.WriteLine($\"Numbers > 3 (descending): {string.Join(\", \", sorted)}\");\n        \n        // Method syntax\n        var sortedMethod = numbers.Where(n => n > 3).OrderByDescending(n => n);\n        Console.WriteLine($\"Method syntax: {string.Join(\", \", sortedMethod)}\");\n    }\n}",
