    question: "Use LINQ to calculate aggregates (Sum, Average, Count, Min, Max).",
    mathSolution: "numbers.Sum(), numbers.Average(), numbers.Count()",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers = { 10, 20, 30, 40, 50 };\n        \n        int sum = numbers.Sum();\n        double avg = numbers.Average();\n        int count = numbers.Count();\n        int min = numbers.Min();\n        int max = numbers.Max();\n        \n        Console.WriteLine($\"Sum: {sum}\");\n        Console.WriteLine($\"Average: {avg}\");\n        Console.WriteLine($\"Count: {count}\");\n        Console.WriteLine($\"Min: {min}\");\n        Console.WriteLine($\"Max: {max}\");\n        \n        // With condition\n        int sumEven = numbers.Where(n => n % 2 == 0).Sum();\n        Console.WriteLine($\"Sum of even numbers: {sumEven}\");\n    }\n}",
    hint: "LINQ provides Sum, Average, Count, Min, Max aggregate methods.",
