    question: "Use LINQ Zip to combine two sequences.",
    mathSolution: "numbers1.Zip(numbers2, (a, b) => a + b)",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers1 = { 1, 2, 3, 4, 5 };\n        int[] numbers2 = { 10, 20, 30, 40, 50 };\n        \n        var sums = numbers1.Zip(numbers2, (a, b) => a + b);\n        Console.WriteLine($\"Sums: {string.Join(\", \", sums)}\");\n        \n        string[] names = { \"Alice\", \"Bob\", \"Charlie\" };\n        int[] ages = { 25, 30, 35 };\n        \n        var people = names.Zip(ages, (name, age) => $\"{name} is {age} years old\");\n        foreach (var person in people)\n            Console.WriteLine(person);\n        \n        // Zip three sequences\n        int[] numbers3 = { 100, 200, 300, 400, 500 };\n        var tripleZip = numbers1.Zip(numbers2, (a, b) => a + b).Zip(numbers3, (ab, c) => ab + c);\n        Console.WriteLine($\"Triple sum: {string.Join(\", \", tripleZip)}\");\n    }\n}",
    hint: "Zip combines two sequences element-wise using a lambda function.",
