    question: "Use LINQ ToDictionary to create dictionary from collection.",
    mathSolution: "products.ToDictionary(p => p.Id, p => p.Name)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Product\n{\n    public int Id { get; set; }\n    public string Name { get; set; }\n    public decimal Price { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Product> products = new List<Product>\n        {\n            new Product { Id = 1, Name = \"Laptop\", Price = 999.99m },\n            new Product { Id = 2, Name = \"Mouse\", Price = 29.99m },\n            new Product { Id = 3, Name = \"Keyboard\", Price = 79.99m }\n        };\n        \n        var productDict = products.ToDictionary(p => p.Id, p => p.Name);\n        \n        foreach (var kvp in productDict)\n            Console.WriteLine($\"ID {kvp.Key}: {kvp.Value}\");\n        \n        // With complex value\n        var fullProductDict = products.ToDictionary(p => p.Id);\n        Console.WriteLine($\"\\nProduct with ID 2: {fullProductDict[2].Name} - ${fullProductDict[2].Price}\");\n    }\n}",
