    mathSolution: "products.ToLookup(p => p.Category)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Product\n{\n    public string Name { get; set; }\n    public string Category { get; set; }\n    public decimal Price { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Product> products = new List<Product>\n        {\n            new Product { Name = \"Laptop\", Category = \"Electronics\", Price = 999.99m },\n            new Product { Name = \"Mouse\", Category = \"Electronics\", Price = 29.99m },\n            new Product { Name = \"Desk\", Category = \"Furniture\", Price = 299.99m },\n            new Product { Name = \"Chair\", Category = \"Furniture\", Price = 149.99m }\n        };\n        \n        var lookup = products.ToLookup(p => p.Category);\n        \n        foreach (var group in lookup)\n        {\n            Console.WriteLine($\"Category: {group.Key}\");\n            foreach (var product in group)\n                Console.WriteLine($\"  {product.Name}: ${product.Price}\");\n        }\n        \n        // Direct access\n        var electronics = lookup[\"Electronics\"];\n        Console.WriteLine($\"\\nElectronics products: {string.Join(\", \", electronics.Select(p => p.Name))}\");\n    }\n}",
