    question: "Use LINQ with multiple from clauses (cross join).",
    mathSolution: "from a in list1 from b in list2 select new { a, b }",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers = { 1, 2, 3 };\n        string[] letters = { \"A\", \"B\" };\n        \n        // Cross join (Cartesian product)\n        var crossJoin = from n in numbers\n                        from l in letters\n                        select $\"{n}{l}\";\n        \n        Console.WriteLine($\"Cross join: {string.Join(\", \", crossJoin)}\");\n        \n        // Filtered cross join\n        var filtered = from n in numbers\n                       from l in letters\n                       where n > 1\n                       select $\"{n}{l}\";\n        \n        Console.WriteLine($\"Filtered cross join (n > 1): {string.Join(\", \", filtered)}\");\n        \n        // Method syntax\n        var crossMethod = numbers.SelectMany(n => letters, (n, l) => $\"{n}{l}\");\n        Console.WriteLine($\"Method syntax: {string.Join(\", \", crossMethod)}\");\n    }\n}",
